	#pragma HLS INTERFACE m_axi port=tensor_cv2_weight depth=27648 offset=slave
	#pragma HLS INTERFACE m_axi port=tensor_fc1_weight depth=884736 offset=slave
	#pragma HLS INTERFACE s_axilite port=tensor_output
	#pragma HLS INTERFACE s_axilite port=return
