	node__cv1_Conv( tensor_input, tensor_cv1_weight, tensor_cv1_bias, tu0.tensor__cv1_Conv_output_0);
	node__cv2_Conv( tu0.tensor__cv1_Conv_output_0, tensor_cv2_weight, tensor_cv2_bias, tu1.tensor__cv2_Conv_output_0);
